                ssc.isAttachmentExist = function () {  
                var attachedfileExist = false;
                $('input:file').each(function(i,v){
                    var data_files = $(this).data('files');
                    if(data_files.length > 0){                       
                        attachedfileExist = true;
                        return false; // breaks the loop
                    }
                });
                return attachedfileExist;};
                ssc.formSubmitModule.config({url_submit_server: 'https://share.spreadsheetconverter.com/submit/',
                before_onlineformsubmit_callback:function(){},
                after_onlineformsubmit_callback : function(status,msg){                    
                    if(status === 'success') {
                        setTimeout(function () {
                            $('#about_done').html('Submitted').attr('disabled', true);
                            setTimeout(function () {
                                $('#about').popup().popup('close');
                                $('#about_done').removeAttr('disabled').html('Submit');
                                var $statusModel = $('#onlinefomsubmit_status_modal');
                                if(ssc.isAttachmentExist()){
                    	             $('input[type=file]').parents('td').find('.uploading').find('ul').find('li').each(function(){ $(this).data('ssc_fileuploader').destroy();});
                                }
                                $statusModel.find('#submit_response').html('<span>Form was successfully submitted.</span>');
                                if($('#xl_redirect_success').length > 0 || false){
                                    $('#onlinefomsubmit_status_modal_close').text('Continue');
                                    $statusModel.find('#onlinefomsubmit_status_modal_close').click(function(){
                                        if($('#xl_redirect_success').length > 0){
                                            var url_ = $('#xl_redirect_success').val();
                                            url_+=(url_.indexOf('paypal')>-1)?'':'';
                                            window.open(url_,'_top');
                                        }else{
                                            window.open('','_top');
                                        }  
                                    });
                                }     
                                //$statusModel.popup().popup('open');
                                showpopup($statusModel);
                            }, 1000);
                        }, 500);
                    }else if(status === 'error') {
                        $('#about').popup().popup('close');
                        $('#about_done').removeAttr('disabled').html('Submit');
                        var $statusModel = $('#onlinefomsubmit_status_modal');
                        $statusModel.find('#submit_response').html('<span>' + msg + '</span>');
                        //$statusModel.popup().popup('open');
                        popup($statusModel);
                    }
                },after_offlineformsubmit_callback : function(){
                    setTimeout(function(){$('#offlineformsubmit_conformation_yes').html('Submitted');
                        setTimeout(function(){$('#offlineformsubmit_conformation_modal').removeAttr('disabled').popup('close');
                            if(ssc.isAttachmentExist()){
                                $('input[type=file]').parents('td').find('.uploading').find('ul').find('li').each(function(){ $(this).data('ssc_fileuploader').destroy();});
                            }
                        },
                            1000);
                    },500);
                }
            });
